INSERT INTO `SystemConfig` (`id`, `storeId`, `key`, `value`, `createdAt`, `updatedAt`) VALUES
  ('seed-config-user-agreement-content', 'seed-store-lotus', 'user_agreement_content', JSON_QUOTE('<h2>用户服务协议</h2><h3>第一章 总则</h3><p>1.1 本《用户服务协议》（以下简称“本协议”）是您（下称“用户”）与本生鲜小程序运营主体就小程序全部线上生鲜订购、配送、会员服务订立的合法有效合约。</p><p>1.2 您在点击登录、勾选同意、使用小程序下单、充值会员前，请完整阅读本协议及配套《隐私政策》；若不认可全部条款，您可点击登录页【取消 / 返回】退出登录，仅以游客身份浏览商品，不可使用下单、配送、售后等核心功能。您完成登录授权，即代表完全知悉、自愿同意本协议全部条款。</p><p>1.3 本小程序为正式运营版本，运营方有权依据法律法规、业务调整更新本协议，更新后将在小程序「我的 - 协议中心」公示，公示 7 日后生效，您继续使用小程序即视为接受新版协议。</p><h3>第二章 平台服务内容</h3><p>2.1 本平台为线上生鲜交易服务平台，正式提供蔬菜、水果、肉禽水产、预制生鲜、月度 / 季度 / 年度生鲜套餐选购、线上下单、配送到家、订单售后、会员储值、订单查询等完整商业服务。</p><p>2.2 平台负责商品展示、订单承接、履约协调、售后保障；生鲜实物由合作农场、生鲜供应商提供，双方构成独立买卖合同关系。</p><p>2.3 平台持续优化功能、更新商品品类、调整配送范围，相关变动将在首页提前公示。</p><h3>第三章 账号登录与授权规范</h3><p>3.1 登录授权规则：平台仅在您主动发起登录时，申请获取微信昵称、头像、OpenID 用于账号识别；如需配送服务，由您自愿填写手机号、收货地址。所有信息收集仅为完成生鲜配送、订单管理、会员权益服务，无其他用途。</p><p>3.2 登录取消权限：登录页面设置独立、可正常响应的【取消 / 返回】按钮，点击后直接退出登录弹窗，跳转小程序首页，平台不得强制、循环唤起登录窗口，不得限制游客浏览商品。</p><p>3.3 账号管理：用户需保证提交信息真实有效，妥善保管自身微信账号，因账号转借、泄露产生的全部损失由用户自行承担；账号仅限本人日常个人采购使用，禁止批量商用、倒卖会员权益。</p><p>3.4 账号限制情形：用户存在恶意刷单、虚假售后、恶意差评、恶意占单、发布违法违规内容等行为时，平台有权限制下单、冻结账号、终止服务。</p><h3>第四章 用户行为规范</h3><p>4.1 用户仅可基于个人家庭生鲜采购需求使用平台服务，禁止利用平台从事牟利倒卖、囤积生鲜、恶意骚扰客服等行为。</p><p>4.2 下单时填写的联系电话、收货地址必须真实有效，因虚假地址、停机电话导致配送失败、食材损耗，相关损失由用户自行承担。</p><p>4.3 禁止爬虫、破解、篡改小程序接口、数据，禁止开发第三方工具劫持平台服务，一经查实平台有权终止服务并保留追责权利。</p><h3>第五章 订单、配送与售后规则</h3><p>5.1 用户提交订单并完成支付，即与供应商成立生鲜买卖合同，平台按照页面公示配送时效履约。</p><p>5.2 生鲜属于鲜活易损耗品类，无变质、缺斤少两、破损等质量问题不支持无理由退货；商品存在质量问题，用户可凭实拍凭证申请售后理赔，平台协助协调退款、补发。</p><p>5.3 月度 / 季度 / 年度生鲜套餐、预付储值卡，按照商品详情页公示规则核销、延期、退款，套餐到期未使用额度按平台统一规则处理。</p><h3>第六章 服务中断、变更与终止</h3><p>6.1 平台可根据运营需求调整商品、配送区域、会员权益，调整内容提前在小程序首页公示。</p><p>6.2 服务器维护、网络故障、自然灾害、交通管制等不可抗力造成服务临时中断，平台将尽可能提前告知，不承担间接损失。</p><p>6.3 用户严重违反本协议、法律法规时，平台可单方面永久终止账号使用权限，并保留追究损失的权利。</p><h3>第七章 法律适用与争议解决</h3><p>7.1 本协议订立、履行、解释全部适用中华人民共和国现行法律。</p><p>7.2 用户与平台产生纠纷，优先通过小程序在线客服协商处理；协商无法达成一致，双方均可向平台运营主体所在地人民法院提起诉讼。</p><p>7.3 平台发布的订单规则、会员规则、售后规则为本协议补充文件，与本协议具备同等法律效力。</p>'), CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
  ('seed-config-privacy-policy-content', 'seed-store-lotus', 'privacy_policy_content', JSON_QUOTE('<h2>隐私政策</h2><h3>第一条 政策说明</h3><p>本《隐私政策》依据《中华人民共和国个人信息保护法》《网络安全法》《电子商务法》制定，向您清晰说明本生鲜小程序如何收集、使用、存储、保护您的个人信息。本政策与《用户服务协议》配套生效，登录前将完整展示；您授权登录即代表知悉并同意本政策；若您不同意信息收集，可点击登录页【取消】按钮，仅游客浏览商品，无法下单、收货、使用会员服务。</p><h3>第二条 我们收集的信息、收集目的与使用范围</h3><p>2.1 微信基础身份信息（昵称、头像、OpenID）：收集场景为您主动点击登录授权时获取，非强制收集，可随时取消登录；使用目的为唯一识别您的用户账号，存储购物车、历史订单、会员套餐权益，区分用户身份，仅用于为您提供生鲜订购配套服务；使用边界为仅在小程序内部使用，不对外出售、租赁、无偿共享给无关第三方。</p><p>2.2 收货联系方式（手机号码、收货详细地址）：收集场景为用户主动下单、填写配送表单时自愿填写；使用目的为生鲜商品配送到家、订单短信通知、售后问题电话沟通，保障订单正常履约交付；订单履约完成后加密留存订单记录用于售后溯源，无售后纠纷后脱敏存储，绝不对外泄露用户联系方式。</p><p>2.3 设备基础日志信息（设备型号、系统版本、操作日志）：用于排查小程序卡顿、闪退等故障，优化正式版产品使用体验，仅做匿名化统计，无法定位到单独自然人。</p><p>2.4 不主动收集的敏感信息：本小程序不会主动申请获取您的相册、麦克风、定位、通讯录、身份证等非必要敏感信息；若后续业务需要新增信息收集，将单独弹窗告知用途，并取得您二次明确授权后方可收集。</p><h3>第三条 个人信息使用规则</h3><p>3.1 全部收集的个人信息仅用于生鲜商城订单履约、会员服务、售后处理，不会用于无关营销骚扰、第三方广告导流。</p><p>3.2 平台正式运营阶段收集的用户数据仅服务于本小程序生鲜业务，不对外批量售卖、共享用户数据。</p><p>3.3 仅在收到公安、法院、市场监管等国家机关合法文书时，才会依法提供对应用户信息。</p><h3>第四条 信息存储与安全防护</h3><p>4.1 用户全部个人信息存储于中国大陆境内合规服务器，不进行跨境传输。</p><p>4.2 平台采用数据加密存储、分级访问权限、操作日志审计等安全技术防护用户信息，定期开展安全巡检，防范信息泄露、篡改、丢失风险。</p><p>4.3 用户个人数据仅授权客服、运维人员有限访问，所有数据操作全程留痕可追溯。</p><h3>第五条 用户享有的个人信息权利</h3><p>5.1 查询、更正权：个人中心可随时查看、修改、删除收货地址、联系电话等个人信息。</p><p>5.2 删除、撤回授权权：您可联系在线客服申请删除全部个人信息，也可在微信小程序设置中关闭用户信息授权，关闭后账号下单、会员功能将受限。</p><h3>第六条 第三方信息共享说明</h3><p>平台不会将您的手机号、微信身份信息出售、出租给任何第三方；仅配送环节会临时同步您的收货地址、手机号给配送人员，仅限本次生鲜配送使用，配送完成后配送端即时清除您的联系方式。</p><h3>第七条 未成年人信息保护</h3><p>本平台面向成年生鲜消费用户，未满 18 周岁未成年人请在监护人陪同下阅读本政策，并经监护人同意后方可使用下单服务；若平台发现未成年人未经监护人许可提交个人信息，监护人可联系客服删除对应全部数据。</p><h3>第八条 政策更新与咨询渠道</h3><p>8.1 平台更新本隐私政策时，将在登录弹窗、「我的 - 协议中心」显著位置公示，公示 7 日后正式生效。</p><p>8.2 关于个人信息收集、隐私安全相关疑问，可通过小程序内客服反馈咨询。</p><h3>第九条 附则</h3><p>9.1 本隐私政策最终解释权归本小程序运营主体所有。</p><p>9.2 本政策自小程序正式商用上线之日起生效。</p>'), CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
ON DUPLICATE KEY UPDATE
  `value` = IF(JSON_UNQUOTE(`value`) = '', VALUES(`value`), `value`),
  `updatedAt` = IF(JSON_UNQUOTE(`value`) = '', VALUES(`updatedAt`), `updatedAt`);
